#include <bits/stdc++.h>
using namespace std;

int main(){
    int n;
    cin>>n;
    vector<string> v;
    for(int i=0;i<n;i++){
        string s;
        cin>>s;
        v.push_back(s);
    }
    int max_len=0;
    for(int i=0;i<n;i++){
        max_len=max(max_len, (int)v[i].length());
    }
    vector<int> visited(26,0);
    for(int i=0;i<n;i++){
        for(int j=0;j<v[i].length();j++){
            visited[v[i][j]-'a']=1;
        }
    }
    char ans='a';
    for(int i=0;i<26;i++){
        if(visited[i]==0){
            ans=i+'a';
            break;
        }
    }
    for(int i=0;i<max_len;i++){
        cout<<ans;
    }
    return 0;
}
